#include <vector>
#include <priority_queue>
#include <tuple>
#include <climits>
#include <utility>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges) {
    vector<vector<tuple<long long, long long, long long>>> adj(n);
    for (auto& e : edges) {
        long long u = e[0];
        long long v = e[1];
        long long s = e[2];
        long long e_end = e[3];
        adj[u].push_back({v, s, e_end});
    }

    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    vector<long long> dist(n, LLONG_MAX);
    dist[0] = 0;
    pq.push({0, 0});

    while (!pq.empty()) {
        long long current_time = pq.top().first;
        long long u = pq.top().second;
        pq.pop();

        if (u == n - 1) {
            return current_time;
        }

        if (current_time > dist[u]) {
            continue;
        }

        for (auto& edge : adj[u]) {
            long long v = get<0>(edge);
            long long s = get<1>(edge);
            long long e_end = get<2>(edge);
            long long earliest_time = max(s, current_time);
            if (earliest_time <= e_end) {
                long long arrival_time = earliest_time + 1;
                if (arrival_time < dist[v]) {
                    dist[v] = arrival_time;
                    pq.push({arrival_time, v});
                }
            }
        }
    }

    return -1;
}

